1	import {
2	  calculateChanges,
3	  logActivity,
4	} from '@/app/api/lib/helpers/activityLogger';
5	import {
6	  applyCurrencyConversionToMetrics,
7	  shouldApplyCurrencyConversion,
8	} from '@/app/api/lib/helpers/currency/helper';
9	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
10	import { Member } from '@/app/api/lib/models/members';
11	import { generateMongoId } from '@/lib/utils/id';
12	import { getClientIP } from '@/lib/utils/ipAddress';
13	import {
14	  logRouteFetch,
15	  logRouteCreate,
16	  logRouteError,
17	  extractUserFromRequest,
18	} from '@/app/api/lib/utils/routeLogger';
19	import type { PipelineStage } from 'mongoose';
20	import type { CurrencyCode } from '@/shared/types/currency';
21	import { NextRequest, NextResponse } from 'next/server';
22	
23	/**
24	 * Main GET handler for fetching members
25	 *
26	 * @param {string} search - Search string for name, username, or ID
27	 * @param {number} page - Page number for pagination (defaults to 1)
28	 * @param {number} limit - Items per page (defaults to 10)
29	 * @param {string} sortBy - Field to sort by (e.g., 'name', 'createdAt')
30	 * @param {string} sortOrder - 'asc' or 'desc'
31	 * @param {string} startDate - Filter by creation date start
32	 * @param {string} endDate - Filter by creation date end
33	 * @param {string} winLossFilter - 'positive', 'negative', or 'all'
34	 * @param {string} locationFilter - Filter by location ID(s)
35	 * @param {string} currency - Display currency code (e.g., 'USD', 'GYD')
36	 * @param {string} licencee - Licencee for currency conversion rules
37	 */
38	export async function GET(request: NextRequest) {
39	  const startTime = Date.now();
40	  const functionName = 'GET /api/members';
41	  const user = extractUserFromRequest(request);
42	
43	  return withApiAuth(request, async () => {
44	    try {
45	      // ============================================================================
46	      // STEP 1: Parse query parameters
47	      // ============================================================================
48	      const { searchParams } = new URL(request.url);
49	      const search = searchParams.get('search') || '';
50	      const page = parseInt(searchParams.get('page') || '1');
51	      const limit = parseInt(searchParams.get('limit') || '10');
52	      const sortBy = searchParams.get('sortBy') || 'createdAt';
53	      const sortOrder = searchParams.get('sortOrder') || 'desc';
54	      const startDate = searchParams.get('startDate');
55	      const endDate = searchParams.get('endDate');
56	      const winLossFilter = searchParams.get('winLossFilter');
57	      const locationFilter = searchParams.get('locationFilter');
58	      const displayCurrency = searchParams.get('currency') || 'USD';
59	      const licencee = searchParams.get('licencee') || null;
60	
61	      // ============================================================================
62	      // STEP 2: Build query filter
63	      // ============================================================================
64	      const query: Record<string, unknown> = {
65	        $or: [
66	          { deletedAt: null },
67	          { deletedAt: { $exists: false } },
68	          { deletedAt: { $lt: new Date('2025-01-01') } },
69	        ],
70	      };
71	
72	      if (search) {
73	        query.$and = [
74	          { $or: query.$or as unknown[] },
75	          {
76	            $or: [
77	              { 'profile.firstName': { $regex: search, $options: 'i' } },
78	              { 'profile.lastName': { $regex: search, $options: 'i' } },
79	              { username: { $regex: search, $options: 'i' } },
80	              { _id: { $regex: search, $options: 'i' } },
81	            ],
82	          },
83	        ];
84	        delete query.$or;
85	      }
86	
87	      if (startDate || endDate) {
88	        const dateFilter: Record<string, unknown> = {};
89	        if (startDate) dateFilter.$gte = new Date(startDate);
90	        if (endDate) dateFilter.$lte = new Date(endDate);
91	        query.createdAt = dateFilter;
92	      }
93	
94	      if (locationFilter && locationFilter !== 'all') {
95	        if (locationFilter.includes(',')) {
96	          query.gamingLocation = { $in: locationFilter.split(',') };
97	        } else {
98	          query.gamingLocation = locationFilter;
99	        }
100	      }
101	
102	      // ============================================================================
103	      // STEP 3: Build relevance and sort options
104	      // ============================================================================
105	      let relevanceStage: PipelineStage | null = null;
106	      if (search) {
107	        const searchTermLower = search.trim();
108	        relevanceStage = {
109	          $addFields: {
110	            relevanceScore: {
111	              $add: [
112	                {
113	                  $cond: [
114	                    {
115	                      $regexMatch: {
116	                        input: { $ifNull: ['$profile.firstName', ''] },
117	                        regex: `^${searchTermLower}`,
118	                        options: 'i',
119	                      },
120	                    },
121	                    20,
122	                    0,
123	                  ],
124	                },
125	                {
126	                  $cond: [
127	                    {
128	                      $regexMatch: {
129	                        input: { $ifNull: ['$profile.lastName', ''] },
130	                        regex: `^${searchTermLower}`,
131	                        options: 'i',
132	                      },
133	                    },
134	                    20,
135	                    0,
136	                  ],
137	                },
138	                {
139	                  $cond: [
140	                    {
141	                      $regexMatch: {
142	                        input: { $ifNull: ['$username', ''] },
143	                        regex: `^${searchTermLower}`,
144	                        options: 'i',
145	                      },
146	                    },
147	                    10,
148	                    0,
149	                  ],
150	                },
151	                {
152	                  $cond: [
153	                    {
154	                      $regexMatch: {
155	                        input: { $toString: '$_id' },
156	                        regex: `^${searchTermLower}`,
157	                        options: 'i',
158	                      },
159	                    },
160	                    10,
161	                    0,
162	                  ],
163	                },
164	              ],
165	            },
166	          },
167	        };
168	      }
169	
170	      const sortOptions: Record<string, number> = {};
171	      if (search) sortOptions['relevanceScore'] = -1;
172	
173	      if (sortBy === 'name') {
174	        sortOptions['profile.firstName'] = sortOrder === 'asc' ? 1 : -1;
175	      } else {
176	        sortOptions[sortBy] = sortOrder === 'asc' ? 1 : -1;
177	      }
178	
179	      // ============================================================================
180	      // STEP 4: Build aggregation pipeline
181	      // ============================================================================
182	      const pipeline: PipelineStage[] = [
183	        { $match: query },
184	        {
185	          $lookup: {
186	            from: 'gaminglocations',
187	            localField: 'gamingLocation',
188	            foreignField: '_id',
189	            as: 'locationInfo',
190	          },
191	        },
192	        {
193	          $lookup: {
194	            from: 'machinesessions',
195	            localField: '_id',
196	            foreignField: 'memberId',
197	            as: 'sessions',
198	          },
199	        },
200	        {
201	          $addFields: {
202	            locationName: { $arrayElemAt: ['$locationInfo.name', 0] },
203	            totalMoneyIn: {
204	              $reduce: {
205	                input: '$sessions',
206	                initialValue: 0,
207	                in: {
208	                  $add: [
209	                    '$$value',
210	                    {
211	                      $ifNull: [
212	                        { $toDouble: '$$this.endMeters.movement.drop' },
213	                        0,
214	                      ],
215	                    },
216	                  ],
217	                },
218	              },
219	            },
220	            totalMoneyOut: {
221	              $reduce: {
222	                input: '$sessions',
223	                initialValue: 0,
224	                in: {
225	                  $add: [
226	                    '$$value',
227	                    {
228	                      $ifNull: [
229	                        {
230	                          $toDouble:
231	                            '$$this.endMeters.movement.totalCancelledCredits',
232	                        },
233	                        0,
234	                      ],
235	                    },
236	                  ],
237	                },
238	              },
239	            },
240	          },
241	        },
242	        {
243	          $addFields: {
244	            winLoss: { $subtract: ['$totalMoneyIn', '$totalMoneyOut'] },
245	            grossRevenue: { $subtract: ['$totalMoneyIn', '$totalMoneyOut'] },
246	          },
247	        },
248	      ];
249	
250	      if (winLossFilter && winLossFilter !== 'all') {
251	        if (winLossFilter === 'positive')
252	          pipeline.push({ $match: { winLoss: { $gt: 0 } } });
253	        else if (winLossFilter === 'negative')
254	          pipeline.push({ $match: { winLoss: { $lt: 0 } } });
255	      }
256	
257	      if (relevanceStage) pipeline.push(relevanceStage);
258	      pipeline.push({ $sort: sortOptions as Record<string, 1 | -1> });
259	
260	      // ============================================================================
261	      // STEP 5: Execute aggregation and calculate pagination
262	      // ============================================================================
263	      const countResult = await Member.aggregate([
264	        ...pipeline,
265	        { $count: 'total' },
266	      ]);
267	      const totalMembers = countResult[0]?.total || 0;
268	
269	      pipeline.push({ $skip: (page - 1) * limit });
270	      pipeline.push({ $limit: limit });
271	
272	      const members = await Member.aggregate(pipeline);
273	
274	      // ============================================================================
275	      // STEP 6: Apply currency conversion
276	      // ============================================================================
277	      const convertedMembers = await applyCurrencyConversionToMetrics(
278	        members,
279	        licencee,
280	        displayCurrency as CurrencyCode
281	      );
282	
283	      const duration = Date.now() - startTime;
284	      logRouteFetch(
285	        functionName,
286	        'GET',
287	        '/api/members',
288	        convertedMembers.length,
289	        user,
290	        duration
291	      );
292	
293	      // ============================================================================
294	      // STEP 7: Return success response
295	      // ============================================================================
296	      return NextResponse.json({
297	        success: true,
298	        data: {
299	          members: convertedMembers,
300	          pagination: {
301	            currentPage: page,
302	            totalPages: Math.ceil(totalMembers / limit),
303	            totalMembers,
304	            hasNextPage: page * limit < totalMembers,
305	            hasPrevPage: page > 1,
306	          },
307	        },
308	        currency: displayCurrency,
309	        converted: shouldApplyCurrencyConversion(licencee),
310	      });
311	    } catch (error) {
312	      const errorMessage =
313	        error instanceof Error ? error.message : 'Internal server error';
314	      logRouteError(functionName, 'GET', '/api/members', errorMessage, user);
315	      return NextResponse.json(
316	        { error: 'Internal server error' },
317	        { status: 500 }
318	      );
319	    }
320	  });
321	}
