323	/**
324	 * Main POST handler for creating a new member
325	 *
326	 * @body {Object} profile - REQUIRED. Member profile data (firstName, lastName, etc.)
327	 * @body {string} username - REQUIRED. Unique username for the member
328	 * @body {string} gamingLocation - Optional. ID of the member's primary gaming location
329	 */
330	export async function POST(request: NextRequest) {
331	  const startTime = Date.now();
332	  const functionName = 'POST /api/members';
333	  const user = extractUserFromRequest(request);
334	
335	  return withApiAuth(request, async ({ user: currentUser }) => {
336	    try {
337	      // ============================================================================
338	      // STEP 1: Parse and validate request body
339	      // ============================================================================
340	      const body = await request.json();
341	      const trimmedFirstName = body.profile?.firstName?.trim();
342	      const trimmedLastName = body.profile?.lastName?.trim();
343	      const trimmedUsername = body.username?.trim();
344	
345	      if (!trimmedFirstName || !trimmedLastName || !trimmedUsername) {
346	        logRouteError(
347	          functionName,
348	          'POST',
349	          '/api/members',
350	          'Missing required fields',
351	          user
352	        );
353	        return NextResponse.json(
354	          { error: 'First name, last name, and username are required' },
355	          { status: 400 }
356	        );
357	      }
358	
359	      // ============================================================================
360	      // STEP 2: Check username uniqueness
361	      // ============================================================================
362	      const existingMember = await Member.findOne({
363	        username: trimmedUsername,
364	      });
365	      if (existingMember) {
366	        logRouteError(
367	          functionName,
368	          'POST',
369	          '/api/members',
370	          'Username already exists',
371	          user
372	        );
373	        return NextResponse.json(
374	          { error: 'Username already exists' },
375	          { status: 400 }
376	        );
377	      }
378	
379	      // ============================================================================
380	      // STEP 3: Create member entry
381	      // ============================================================================
382	      const memberId = await generateMongoId();
383	      const newMember = new Member({
384	        _id: memberId,
385	        username: trimmedUsername,
386	        profile: {
387	          ...body.profile,
388	          firstName: trimmedFirstName,
389	          lastName: trimmedLastName,
390	        },
391	        gamingLocation: body.gamingLocation || 'default',
392	        createdAt: new Date(),
393	        updatedAt: new Date(),
394	        // ... include other default fields as per schema requirements
395	      });
396	
397	      await newMember.save();
398	
399	      const duration = Date.now() - startTime;
400	      logRouteCreate(functionName, 'POST', '/api/members', 1, user, duration);
401	
402	      // ============================================================================
403	      // STEP 4: Log activity
404	      // ============================================================================
405	      if (currentUser?._id) {
406	        try {
407	          const changes = calculateChanges(
408	            {},
409	            newMember.toObject ? newMember.toObject() : newMember
410	          );
411	
412	          await logActivity({
413	            action: 'CREATE',
414	            details: `Created new member "${trimmedFirstName} ${trimmedLastName}"`,
415	            ipAddress: getClientIP(request) || undefined,
416	            userAgent: request.headers.get('user-agent') || undefined,
417	            userId: currentUser._id as string,
418	            username:
419	              (currentUser.username as string) ||
420	              (currentUser.emailAddress as string) ||
421	              'unknown',
422	            metadata: {
423	              resource: 'member',
424	              resourceId: newMember._id,
425	              resourceName: `${trimmedFirstName} ${trimmedLastName}`,
426	              changes,
427	              previousData: null,
428	              newData: newMember.toObject ? newMember.toObject() : newMember,
429	            },
430	          });
431	        } catch (logError) {
432	          console.error('Failed to log activity:', logError);
433	        }
434	      }
435	
436	      // ============================================================================
437	      // STEP 5: Return success response
438	      // ============================================================================
439	      return NextResponse.json(newMember, { status: 201 });
440	    } catch (error) {
441	      const errorMessage =
442	        error instanceof Error ? error.message : 'Internal server error';
443	      logRouteError(functionName, 'POST', '/api/members', errorMessage, user);
444	      return NextResponse.json(
445	        { error: 'Internal server error' },
446	        { status: 500 }
447	      );
448	    }
449	  });
450	}
