1	/**
2	 * Member by ID API Route
3	 *
4	 * This route handles CRUD operations for a specific member by ID.
5	 * It supports:
6	 * - Fetching member details with location information
7	 * - Updating member profile and settings
8	 * - Soft deleting members
9	 *
10	 * @module app/api/members/[id]/route
11	 */
12	
13	import {
14	  calculateChanges,
15	  logActivity,
16	  mapDeletedFieldsToChanges,
17	} from '@/app/api/lib/helpers/activityLogger';
18	import { getUserFromServer } from '@/app/api/lib/helpers/users';
19	import { connectDB } from '@/app/api/lib/middleware/db';
20	import { Member } from '@/app/api/lib/models/members';
21	import {
22	  logRouteFetch,
23	  logRouteUpdate,
24	  logRouteDelete,
25	  logRouteError,
26	  extractUserFromRequest,
27	} from '@/app/api/lib/utils/routeLogger';
28	import { NextRequest, NextResponse } from 'next/server';
29	import {
30	  fetchMemberWithLocation,
31	  updateMemberProfileFields,
32	  checkMemberFieldUniqueness,
33	  softDeleteMember,
34	  buildDeleteActivityParams,
35	} from '@/app/api/lib/helpers/members/memberByIdOperations';
36	
37	/**
38	 * GET /api/members/[id]
39	 *
40	 * Fetches a single member document with its associated gaming location name joined
41	 * via aggregation; used by the Member Details page to populate the member profile view.
42	 *
43	 * URL params:
44	 * @param id {string} Required (path). The string `_id` of the member to retrieve.
45	 */
46	export async function GET(request: NextRequest) {
47	  const startTime = Date.now();
48	  const functionName = 'GET /api/members/[id]';
49	  const user = extractUserFromRequest(request);
50	
51	  try {
52	    // ============================================================================
53	    // STEP 1: Parse route parameters
54	    // ============================================================================
55	    const { pathname } = request.nextUrl;
56	    const id = pathname.split('/').pop();
57	
58	    // ============================================================================
59	    // STEP 2: Connect to database
60	    // ============================================================================
61	    await connectDB();
62	
63	    // ============================================================================
64	    // STEP 3: Fetch member with location information using aggregation
65	    // ============================================================================
66	    const member = await fetchMemberWithLocation(id || '');
67	
68	    // ============================================================================
69	    // STEP 4: Return member data
70	    // ============================================================================
71	    if (!member) {
72	      logRouteError(functionName, 'GET', '/api/members/[id]', `Not found: ${id}`, user);
73	      return NextResponse.json(
74	        { success: false, error: 'Member not found' },
75	        { status: 404 }
76	      );
77	    }
78	
79	    const duration = Date.now() - startTime;
80	    logRouteFetch(functionName, 'GET', '/api/members/[id]', 1, user, duration);
81	    return NextResponse.json(member);
82	  } catch (error) {
83	    const errorMessage = error instanceof Error ? error.message : 'Internal server error';
84	    logRouteError(functionName, 'GET', '/api/members/[id]', errorMessage, user);
85	    return NextResponse.json(
86	      { success: false, error: errorMessage },
87	      { status: 500 }
88	    );
89	  }
90	}
