92	/**
93	 * PUT /api/members/[id]
94	 *
95	 * Updates a member's profile and account settings; restricted to admin and developer
96	 * roles. Changes are activity-logged with a before/after diff. Requires the caller
97	 * to be authenticated via session cookie.
98	 *
99	 * URL params:
100	 * @param id {string} Required (path). The string `_id` of the member to update.
101	 *
102	 * Body fields (all optional; only provided keys are applied):
103	 * @param profile          {object}  Nested profile sub-document. Accepted sub-fields:
104	 *                                    `firstName` {string} — member's given name.
105	 *                                    `lastName`  {string} — member's family name.
106	 *                                    `email`     {string} — contact email; must be unique.
107	 *                                    `occupation` {string} — member's stated occupation.
108	 *                                    `address`   {string} — member's physical address.
109	 *                                    `gender`    {string} — member's gender.
110	 *                                    `dob`       {string} — date of birth (ISO string or locale date).
111	 * @param username         {string}  Member's login/display username; must be unique.
112	 * @param phoneNumber      {string}  Member's contact phone number.
113	 * @param points           {number}  Current loyalty points balance.
114	 * @param uaccount         {unknown} Universal account reference object.
115	 * @param gamingLocation   {string}  ID of the gaming location this member belongs to.
116	 */
117	export async function PUT(request: NextRequest) {
118	  const startTime = Date.now();
119	  const functionName = 'PUT /api/members/[id]';
120	  const user = extractUserFromRequest(request);
121	
122	  try {
123	    // ============================================================================
124	    // STEP 1: Parse route parameters and request body
125	    // ============================================================================
126	    const { pathname } = request.nextUrl;
127	    const memberId = pathname.split('/').pop();
128	    const body = await request.json();
129	
130	    console.log(`[Member PUT] Request — member: ${memberId}`);
131	
132	    // ============================================================================
133	    // STEP 2: Validate member ID
134	    // ============================================================================
135	    if (!memberId) {
136	      return NextResponse.json({ error: 'Member ID is required' }, { status: 400 });
137	    }
138	
139	    // ============================================================================
140	    // STEP 3: Connect to database and authenticate user
141	    // ============================================================================
142	    await connectDB();
143	    const userPayload = await getUserFromServer();
144	
145	    if (!userPayload) {
146	      logRouteError(functionName, 'PUT', '/api/members/[id]', 'Unauthorized', user);
147	      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
148	    }
149	
150	    const userRoles = (userPayload.roles as string[]) || [];
151	    const isAdminOrDeveloper = userRoles.some(
152	      role => role === 'admin' || role === 'developer'
153	    );
154	
155	    if (!isAdminOrDeveloper) {
156	      logRouteError(functionName, 'PUT', '/api/members/[id]', 'Forbidden - insufficient permissions', user);
157	      return NextResponse.json(
158	        { error: 'Forbidden: Only administrators and developers can edit members' },
159	        { status: 403 }
160	      );
161	    }
162	
163	    // ============================================================================
164	    // STEP 4: Find member by ID
165	    // ============================================================================
166	    const member = await Member.findOne({ _id: memberId });
167	
168	    if (!member) {
169	      logRouteError(functionName, 'PUT', '/api/members/[id]', `Member not found: ${memberId}`, user);
170	      return NextResponse.json({ error: 'Member not found' }, { status: 404 });
171	    }
172	
173	    const originalMemberData = member.toObject();
174	
175	    // ============================================================================
176	    // STEP 5: Update member fields
177	    // ============================================================================
178	    if (body.profile !== undefined) {
179	      if (!member.profile) {
180	        member.profile = {
181	          firstName: '',
182	          lastName: '',
183	          email: '',
184	          occupation: '',
185	          address: '',
186	          gender: '',
187	          dob: '',
188	          indentification: { number: '', type: '' },
189	        };
190	      }
191	
192	      const trimString = (value: unknown): string =>
193	        typeof value === 'string' ? value.trim() : '';
194	
195	      if (body.profile.firstName !== undefined) {
196	        const trimmed = trimString(body.profile.firstName);
197	        if (!trimmed) {
198	          return NextResponse.json({ error: 'First name cannot be blank' }, { status: 400 });
199	        }
200	      }
201	      if (body.profile.lastName !== undefined) {
202	        const trimmed = trimString(body.profile.lastName);
203	        if (!trimmed) {
204	          return NextResponse.json({ error: 'Last name cannot be blank' }, { status: 400 });
205	        }
206	      }
207	      if (body.profile.email !== undefined) {
208	        const trimmedEmail = trimString(body.profile.email);
209	        if (trimmedEmail) {
210	          const exists = await checkMemberFieldUniqueness('profile.email', trimmedEmail, memberId);
211	          if (exists) {
212	            logRouteError(functionName, 'PUT', '/api/members/[id]', 'Email address already in use', user);
213	            return NextResponse.json({ error: 'Email address already in use' }, { status: 400 });
214	          }
215	        }
216	      }
217	
218	      const updatedProfile = updateMemberProfileFields(
219	        member.profile as Record<string, unknown>,
220	        body.profile
221	      );
222	      if (updatedProfile) {
223	        member.profile = updatedProfile;
224	      }
225	    }
226	
227	    if (body.username !== undefined) {
228	      const trimmedUsername = typeof body.username === 'string' ? body.username.trim() : '';
229	      if (!trimmedUsername) {
230	        return NextResponse.json({ error: 'Username is required and cannot be blank' }, { status: 400 });
231	      }
232	      const exists = await checkMemberFieldUniqueness('username', trimmedUsername, memberId);
233	      if (exists) {
234	        logRouteError(functionName, 'PUT', '/api/members/[id]', 'Username already exists', user);
235	        return NextResponse.json({ error: 'Username already exists' }, { status: 400 });
236	      }
237	      member.username = trimmedUsername;
238	    }
239	
240	    if (body.phoneNumber !== undefined) {
241	      member.phoneNumber = typeof body.phoneNumber === 'string' ? body.phoneNumber.trim() : body.phoneNumber;
242	    }
243	    if (body.points !== undefined) {
244	      member.points = body.points;
245	    }
246	    if (body.uaccount !== undefined) {
247	      member.uaccount = body.uaccount;
248	    }
249	    if (body.gamingLocation !== undefined) {
