30	/**
31	 * Helper function to calculate ISO week number
32	 */
33	function getWeekNumber(date: Date): number {
34	  const adjustedDate = new Date(
35	    Date.UTC(date.getFullYear(), date.getMonth(), date.getDate())
36	  );
37	  const dayNum = adjustedDate.getUTCDay() || 7;
38	  adjustedDate.setUTCDate(adjustedDate.getUTCDate() + 4 - dayNum);
39	  const yearStart = new Date(Date.UTC(adjustedDate.getUTCFullYear(), 0, 1));
40	  return Math.ceil(
41	    ((adjustedDate.getTime() - yearStart.getTime()) / 86400000 + 1) / 7
42	  );
43	}
