45	/**
46	 * GET /api/members/[id]/sessions
47	 *
48	 * Fetches machine sessions for a specific member with optional date filtering,
49	 * time-period presets, and display-currency conversion. When `filter` is `session`
50	 * the response is paginated individual rows; any other value groups sessions by
51	 * day, week, or month and returns a single aggregated page.
52	 *
53	 * URL params:
54	 * @param {string} id - Required (path). The string `_id` of the member whose sessions are fetched.
55	 *
56	 * Query params:
57	 * @param {number} [page] - Optional. 1-based page number for individual session pagination (default: 1).
58	 *                             Ignored when `filter` is not `session`.
59	 * @param {number} [limit] - Optional. Number of sessions per page (default: 10).
60	 *                             Ignored when `filter` is not `session`.
61	 * @param {string} [filter] - Optional. Controls result shape. `session` (default) returns individual rows;
62	 *                             `day`, `week`, or `month` collapses sessions into aggregate groups.
63	 * @param {string} [displayCurrency] - Optional. ISO currency code to convert financial metrics into
64	 *                             (e.g. `"TTD"`, `"USD"`). Resolved via `getCurrencyFromQuery`.
65	 * @param {string} [licencee] - Optional. Licencee ID used to look up the currency conversion rate
66	 *                             for the location. If absent, conversion is skipped.
67	 * @param {string} [startDate] - Optional. ISO date string for the start of a custom date range.
68	 *                             Must be paired with `endDate`; filters `startTime >= startDate`.
69	 * @param {string} [endDate] - Optional. ISO date string for the end of a custom date range.
70	 *                             Must be paired with `startDate`; filters `startTime < endDate + 1 day`.
71	 * @param {string} [timePeriod] - Optional. Preset time window applied when `startDate`/`endDate` are absent.
72	 *                             Accepted values: `today`, `yesterday`, `7d`, `30d`, `all time`.
73	 */
74	export async function GET(request: NextRequest) {
75	  const startTime = Date.now();
76	  const functionName = 'GET /api/members/[id]/sessions';
77	  const user = extractUserFromRequest(request);
78	
79	  try {
80	    // ============================================================================
81	    // STEP 1: Parse route parameters
82	    // ============================================================================
83	    const { pathname } = request.nextUrl;
84	    const parts = pathname.split('/');
85	    const id = parts[parts.length - 2]; // Extract [id] from /api/members/[id]/sessions
86	
87	    // ============================================================================
88	    // STEP 2: Connect to database
89	    // ============================================================================
90	    await connectDB();
91	
92	    // ============================================================================
93	    // STEP 3: Build query for member sessions
94	    // ============================================================================
95	
96	    const { searchParams } = new URL(request.url);
97	    const page = parseInt(searchParams.get('page') || '1');
98	    const limit = parseInt(searchParams.get('limit') || '10');
99	    const filter = searchParams.get('filter') || 'session';
100	    const displayCurrency = getCurrencyFromQuery(searchParams);
101	    const licencee = searchParams.get('licencee') || null;
102	    const startDateParam = searchParams.get('startDate');
103	    const endDateParam = searchParams.get('endDate');
104	    const timePeriod = searchParams.get('timePeriod');
105	
106	    const query: Record<string, unknown> = { memberId: id };
107	
108	    // Date filtering logic
109	    if (startDateParam && endDateParam) {
110	      const start = new Date(startDateParam);
111	      // Create end date and add 1 day to make it inclusive (less than next day)
112	      const end = new Date(endDateParam);
113	      end.setUTCDate(end.getUTCDate() + 1);
114	
115	      query.startTime = {
116	        $gte: start,
117	        $lt: end,
118	      };
119	    } else if (timePeriod) {
120	      const now = new Date();
121	      // Reset to start of today (local time as base, but could be UTC depending on server)
122	      // Usually matching the 'today' logic of the dashboard
123	      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
124	
125	      switch (timePeriod) {
126	        case 'today':
127	          query.startTime = {
128	            $gte: today,
129	            $lt: new Date(today.getTime() + 24 * 60 * 60 * 1000),
130	          };
131	          break;
132	        case 'yesterday':
133	          const yesterday = new Date(today);
134	          yesterday.setDate(yesterday.getDate() - 1);
135	          query.startTime = {
136	            $gte: yesterday,
137	            $lt: today,
138	          };
139	          break;
140	        case '7d':
141	          const sevenDaysAgo = new Date(today);
142	          sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
143	          query.startTime = { $gte: sevenDaysAgo };
144	          break;
145	        case '30d':
146	          const thirtyDaysAgo = new Date(today);
147	          thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
148	          query.startTime = { $gte: thirtyDaysAgo };
149	          break;
150	        case 'all time':
151	          // No filter
152	          break;
153	      }
154	    }
155	
156	    // ============================================================================
157	    // STEP 4: Handle individual session view or grouped view
158	    // ============================================================================
159	    if (filter === 'session') {
160	      // ============================================================================
161	      // STEP 5: Process individual sessions
162	      // ============================================================================
163	      const totalSessions = await MachineSession.countDocuments(query);
164	
165	      const sessions = await MachineSession.find(query)
166	        .sort({ startTime: -1 })
167	        .skip((page - 1) * limit)
168	        .limit(limit)
169	        .lean<MachineSessionDocument[]>();
170	
171	      const processedSessions = sessions.map(session => {
172	        let duration = null;
173	        let sessionLength = 'N/A';
174	
175	        if (session.startTime && session.endTime) {
176	          const start = new Date(session.startTime);
177	          const end = new Date(session.endTime);
178	          const durationMs = end.getTime() - start.getTime();
179	          duration = Math.round(durationMs / (1000 * 60)); // Duration in minutes
180	
181	          // Format session length as HH:MM:SS
182	          const hours = Math.floor(durationMs / (1000 * 60 * 60));
183	          const minutes = Math.floor(
184	            (durationMs % (1000 * 60 * 60)) / (1000 * 60)
185	          );
186	          const seconds = Math.floor((durationMs % (1000 * 60)) / 1000);
187	          sessionLength = `${hours.toString().padStart(2, '0')}:${minutes
188	            .toString()
189	            .padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
190	        }
191	
192	        // Calculate handle (total bets placed) - using movement.coinIn from financial guide
193	        const handle = session.endMeters?.movement?.coinIn || 0;
194	
195	        // Calculate money in (physical cash inserted) from endMeters using financial guide
196	        const moneyIn = session.endMeters?.movement?.drop || 0;
197	
198	        // Calculate money out (manual payouts) from endMeters using financial guide
199	        const moneyOut =
200	          session.endMeters?.movement?.totalCancelledCredits || 0;
201	
202	        // Calculate jackpot from endMeters using movement field
203	        const jackpot = session.endMeters?.movement?.jackpot || 0;
204	
205	        // Calculate coin in/out from endMeters using movement fields
206	        const coinIn = session.endMeters?.movement?.coinIn || 0;
207	        const coinOut = session.endMeters?.movement?.coinOut || 0;
208	
209	        // Calculate won/less (coin out - coin in)
210	        const wonLess = Number(coinOut) - Number(coinIn);
211	
212	        // Calculate bet (coin in)
213	        const bet = coinIn;
214	
215	        // Calculate won (coin out)
216	        const won = coinOut;
217	
218	        return {
219	          _id: session._id,
220	          sessionId: session._id,
221	          machineId: session.machineId,
222	          time: session.startTime
223	            ? new Date(session.startTime).toLocaleString('en-US', {
224	                day: 'numeric',
225	                month: 'short',
226	                year: 'numeric',
227	                hour: '2-digit',
228	                minute: '2-digit',
229	                hour12: true,
230	              })
231	            : 'N/A',
232	          sessionLength,
233	          handle,
234	          moneyIn,
235	          moneyOut,
236	          jackpot,
237	          won,
238	          bet,
239	          wonLess,
240	          points: session.points || 0,
241	          gamesPlayed: session.endMeters?.movement?.gamesPlayed || 0,
242	          gamesWon: session.endMeters?.movement?.gamesWon || 0,
243	          coinIn,
244	          coinOut,
245	          duration,
246	        };
247	      });
248	
249	      // ============================================================================
250	      // STEP 6: Apply currency conversion if needed
251	      // ============================================================================
252	      const convertedSessions = await applyCurrencyConversionToMetrics(
253	        processedSessions,
254	        licencee,
255	        displayCurrency
256	      );
257	
258	      // ============================================================================
259	      // STEP 7: Return paginated results
260	      // ============================================================================
261	      const duration = Date.now() - startTime;
262	      logRouteFetch(
263	        functionName,
264	        'GET',
265	        '/api/members/[id]/sessions',
266	        convertedSessions.length,
267	        user,
268	        duration
269	      );
270	
271	      return NextResponse.json({
272	        success: true,
273	        data: {
274	          sessions: convertedSessions,
275	          pagination: {
276	            currentPage: page,
277	            totalPages: Math.ceil(totalSessions / limit),
278	            totalSessions,
279	            hasNextPage: page < Math.ceil(totalSessions / limit),
280	            hasPrevPage: page > 1,
281	          },
282	        },
283	        currency: displayCurrency,
284	        converted: shouldApplyCurrencyConversion(licencee),
285	      });
286	    } else {
287	      // ============================================================================
288	      // STEP 5: Process grouped sessions
289	      // ============================================================================
290	      const allSessions = await MachineSession.find(query)
291	        .sort({ startTime: -1 })
292	        .lean<MachineSessionDocument[]>();
293	
294	      const groupedSessions = new Map();
295	
296	      allSessions.forEach(session => {
297	        if (session.startTime) {
298	          const sessionDate = new Date(session.startTime);
299	          let groupKey: string;
300	
301	          switch (filter) {
302	            case 'day':
303	              groupKey = sessionDate.toLocaleDateString('en-US', {
304	                month: 'long',
305	                day: 'numeric',
306	                year: 'numeric',
307	              });
308	              break;
309	            case 'week':
310	              const weekStart = new Date(sessionDate);
311	              const dayOfWeek = sessionDate.getDay();
312	              const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
313	              weekStart.setDate(sessionDate.getDate() - daysToSubtract);
314	              weekStart.setHours(0, 0, 0, 0);
315	
316	              // Calculate week number (ISO week number)
317	              const weekNumber = getWeekNumber(weekStart);
318	
319	              groupKey = `Week ${weekNumber}, ${weekStart.toLocaleDateString(
320	                'en-US',
321	                {
322	                  month: 'long',
323	                  day: 'numeric',
324	                  year: 'numeric',
325	                }
326	              )}`;
327	              break;
328	            case 'month':
329	              groupKey = sessionDate.toLocaleDateString('en-US', {
330	                month: 'long',
331	                year: 'numeric',
332	              });
333	              break;
334	            default:
335	              groupKey = sessionDate.toLocaleDateString('en-US', {
336	                month: 'long',
337	                day: 'numeric',
338	                year: 'numeric',
339	              });
340	          }
341	
342	          if (!groupedSessions.has(groupKey)) {
343	            groupedSessions.set(groupKey, {
344	              _id: groupKey,
345	              sessionId: groupKey,
346	              machineId: 'N/A',
347	              time: groupKey,
348	              sessionLength: 'N/A',
349	              handle: 0,
350	              moneyIn: 0,
351	              moneyOut: 0,
352	              jackpot: 0,
353	              won: 0,
354	              bet: 0,
355	              wonLess: 0,
356	              points: 0,
357	              gamesPlayed: 0,
358	              gamesWon: 0,
359	              coinIn: 0,
360	              coinOut: 0,
361	              duration: 0,
362	              sessionCount: 0,
363	              totalDuration: 0,
364	            });
365	          }
366	
367	          const group = groupedSessions.get(groupKey);
368	
369	          // Calculate session metrics
370	          const handle = session.endMeters?.movement?.coinIn || 0;
371	          const moneyIn = session.endMeters?.movement?.drop || 0;
372	          const moneyOut =
373	            session.endMeters?.movement?.totalCancelledCredits || 0;
374	          const jackpot = session.endMeters?.movement?.jackpot || 0;
375	          const coinIn = session.endMeters?.movement?.coinIn || 0;
376	          const coinOut = session.endMeters?.movement?.coinOut || 0;
377	          const wonLess = Number(coinOut) - Number(coinIn);
378	          const bet = coinIn;
379	          const won = coinOut;
380	
381	          // Sum up all metrics
382	          group.handle += handle;
383	          group.moneyIn += moneyIn;
384	          group.moneyOut += moneyOut;
385	          group.jackpot += jackpot;
386	          group.won += won;
387	          group.bet += bet;
388	          group.wonLess += wonLess;
389	          group.points += session.points || 0;
390	          group.gamesPlayed += session.endMeters?.movement?.gamesPlayed || 0;
391	          group.gamesWon += session.endMeters?.movement?.gamesWon || 0;
392	          group.coinIn += coinIn;
393	          group.coinOut += coinOut;
394	          group.sessionCount += 1;
395	
396	          // Calculate total duration
397	          if (session.startTime && session.endTime) {
398	            const start = new Date(session.startTime);
399	            const end = new Date(session.endTime);
400	            const durationMs = end.getTime() - start.getTime();
401	            group.totalDuration += durationMs;
402	          }
403	        }
404	      });
405	
406	      // Convert grouped sessions to array and format duration
407	      const processedSessions = Array.from(groupedSessions.values()).map(
408	        group => {
409	          // Format total duration as HH:MM:SS
410	          const hours = Math.floor(group.totalDuration / (1000 * 60 * 60));
411	          const minutes = Math.floor(
412	            (group.totalDuration % (1000 * 60 * 60)) / (1000 * 60)
413	          );
414	          const seconds = Math.floor(
415	            (group.totalDuration % (1000 * 60)) / 1000
416	          );
417	          const sessionLength = `${hours.toString().padStart(2, '0')}:${minutes
418	            .toString()
419	            .padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
420	
421	          return {
422	            ...group,
423	            sessionLength,
424	            time: group.time,
425	          };
426	        }
427	      );
428	
429	      processedSessions.sort(
430	        (a: Record<string, unknown>, b: Record<string, unknown>) =>
431	          new Date(b.time as string).getTime() -
432	          new Date(a.time as string).getTime()
433	      );
434	
435	      // ============================================================================
436	      // STEP 6: Apply currency conversion if needed
437	      // ============================================================================
438	      const convertedGroupedSessions = await applyCurrencyConversionToMetrics(
439	        processedSessions,
440	        licencee,
441	        displayCurrency
442	      );
443	
444	      // ============================================================================
445	      // STEP 7: Return paginated results
446	      // ============================================================================
447	      const duration = Date.now() - startTime;
448	      logRouteFetch(
449	        functionName,
450	        'GET',
451	        '/api/members/[id]/sessions',
452	        convertedGroupedSessions.length,
453	        user,
454	        duration
455	      );
456	
457	      return NextResponse.json({
458	        success: true,
459	        data: {
460	          sessions: convertedGroupedSessions,
461	          pagination: {
462	            currentPage: 1,
463	            totalPages: 1,
464	            totalSessions: processedSessions.length,
465	            hasNextPage: false,
466	            hasPrevPage: false,
467	          },
468	        },
469	        currency: displayCurrency,
470	        converted: shouldApplyCurrencyConversion(licencee),
471	      });
472	    }
473	  } catch (error) {
474	    const duration = Date.now() - startTime;
475	    const errorMessage =
476	      error instanceof Error ? error.message : 'Internal server error';
477	    logRouteError(
478	      functionName,
479	      'GET',
480	      '/api/members/[id]/sessions',
481	      errorMessage,
482	      user
483	    );
484	    console.error(
485	      `[Member Sessions API] Error after ${duration}ms:`,
486	      errorMessage
487	    );
488	    return NextResponse.json(
489	      { success: false, error: errorMessage },
490	      { status: 500 }
491	    );
492	  }
493	}
