28	 *
29	 * @param {string} dateFilter - Time period preset ('yesterday', 'week', 'month', 'custom', 'all')
30	 * @param {string} startDate - ISO date string for custom filter start
31	 * @param {string} endDate - ISO date string for custom filter end
32	 * @param {string} search - Search query for name, phone, or username
33	 * @param {string} location - Filter by location ID(s)
34	 * @param {string} licencee - Optional. Filter by licencee (ID or name)
35	 * @param {number} page - Page number for pagination
36	 * @param {number} limit - Items per page
37	 *
38	 * Flow:
39	 * 1. Connect to database
40	 * 2. Parse query parameters
41	 * 3. Build date filter conditions
42	 * 4. Handle licencee filtering through location lookup
43	 * 5. Add location and search filters
44	 * 6. Get total count for pagination
45	 * 7. Aggregate member data with financial metrics
46	 * 8. Calculate summary statistics
47	 * 9. Return paginated results with summary
48	 */
49	export async function GET(request: NextRequest) {
50	  const startTime = Date.now();
51	  const functionName = 'GET /api/members/summary';
52	  const user = extractUserFromRequest(request);
53	
54	  try {
55	    // ============================================================================
56	    // STEP 1: Connect to database
57	    // ============================================================================
58	    await connectDB();
59	
60	    // ============================================================================
61	    // STEP 2: Parse query parameters
62	    // ============================================================================
63	
64	    // Example: GET /api/members/summary?licencee=9a5db2cb29ffd2d962fd1d91&page=1&limit=10&search=John&location=6801f2a3b4c5d6e7f8901234
65	    const { searchParams } = new URL(request.url);
66	    // Licencee filtering removed - show all members regardless of licencee
67	    const dateFilter = searchParams.get('dateFilter') || 'all';
68	    const startDate = searchParams.get('startDate');
69	    const endDate = searchParams.get('endDate');
70	    const searchTerm = searchParams.get('search') || '';
71	    const locationFilter = searchParams.get('location') || '';
72	    const page = parseInt(searchParams.get('page') || '1');
73	    const limit = parseInt(searchParams.get('limit') || '10');
74	    const skip = (page - 1) * limit;
75	
76	    // ============================================================================
77	    // STEP 3: Build date filter conditions
78	    // ============================================================================
79	    // Base match conditions - exclude only members deleted in 2025 or later
80	    const matchConditions: Record<string, unknown> = {
81	      $or: [
82	        { deletedAt: null },
83	        { deletedAt: { $exists: false } },
84	        { deletedAt: { $lt: new Date('2025-01-01') } }, // Include items deleted before 2025
85	      ],
86	    };
87	    const dateFilterConditions: Record<string, unknown> = {};
88	
89	    // Build date filter for sessions (not for members - we want to show all members)
90	    // Date filter will be applied to sessions lookup, not to member matching
91	    let sessionDateFilter: Record<string, unknown> = {};
92	    if (dateFilter !== 'all') {
93	      let dateQuery: Record<string, unknown> = {};
94	      // For sessions, we filter by session date, not member lastLogin/createdAt
95	      const dateField = 'startTime'; // Filter sessions by startTime
96	
97	      if (dateFilter === 'custom' && startDate && endDate) {
98	        dateQuery = {
99	          [dateField]: {
100	            $gte: new Date(startDate),
101	            $lte: new Date(endDate),
102	          },
103	        };
104	      } else if (dateFilter === 'yesterday') {
105	        const yesterday = new Date();
106	        yesterday.setDate(yesterday.getDate() - 1);
107	        dateQuery = {
108	          [dateField]: {
109	            $gte: new Date(yesterday.setHours(0, 0, 0, 0)),
110	            $lt: new Date(yesterday.setHours(23, 59, 59, 999)),
111	          },
112	        };
113	      } else if (dateFilter === 'week') {
114	        const weekAgo = new Date();
115	        weekAgo.setDate(weekAgo.getDate() - 7);
116	        dateQuery = {
117	          [dateField]: { $gte: weekAgo },
118	        };
119	      } else if (dateFilter === 'month') {
120	        const monthAgo = new Date();
121	        monthAgo.setMonth(monthAgo.getMonth() - 1);
122	        dateQuery = {
123	          [dateField]: { $gte: monthAgo },
124	        };
125	      }
126	      if (Object.keys(dateQuery).length > 0) {
127	        sessionDateFilter = dateQuery;
128	        // Store for use in session lookup
129	        Object.assign(dateFilterConditions, dateQuery);
130	      }
131	    }
132	
133	    // ============================================================================
134	    // STEP 4: Handle location filtering (licencee filtering removed - show all members)
135	    // ============================================================================
136	    // Add location filter if specified (but no licencee filtering)
137	    if (locationFilter && locationFilter !== 'all') {
138	      if (locationFilter.includes(',')) {
139	        matchConditions.gamingLocation = { $in: locationFilter.split(',') };
140	      } else {
141	        matchConditions.gamingLocation = locationFilter;
142	      }
143	    }
144	
145	    // ============================================================================
146	    // STEP 5: Add location and search filters
147	    // ============================================================================
148	    if (searchTerm) {
149	      // If we already have $or for deletedAt, we need to use $and to combine
150	      if (matchConditions.$or && Array.isArray(matchConditions.$or)) {
151	        const existingOr = matchConditions.$or;
152	        matchConditions.$and = [
153	          { $or: existingOr },
154	          {
155	            $or: [
156	              { 'profile.firstName': { $regex: searchTerm, $options: 'i' } },
157	              { 'profile.lastName': { $regex: searchTerm, $options: 'i' } },
158	              { phoneNumber: { $regex: searchTerm, $options: 'i' } },
159	              { username: { $regex: searchTerm, $options: 'i' } },
160	            ],
161	          },
162	        ];
163	        delete matchConditions.$or;
164	      } else {
165	        matchConditions.$or = [
166	          { 'profile.firstName': { $regex: searchTerm, $options: 'i' } },
167	          { 'profile.lastName': { $regex: searchTerm, $options: 'i' } },
168	          { phoneNumber: { $regex: searchTerm, $options: 'i' } },
169	          { username: { $regex: searchTerm, $options: 'i' } },
170	        ];
171	      }
172	    }
173	
174	    // ============================================================================
175	    // STEP 6: Get total count for pagination (includes date filter)
176	    // ============================================================================
177	    const totalCount = await Member.countDocuments(matchConditions);
178	
179	    // Get total members count (excluding date filter but including location filter if provided) for summary stats
180	    // totalMembers should count members filtered by location if location filter is provided
181	    const totalMembersConditions: Record<string, unknown> = {
182	      $or: [
183	        { deletedAt: null },
184	        { deletedAt: { $exists: false } },
185	        { deletedAt: { $lt: new Date('2025-01-01') } }, // Include items deleted before 2025
186	      ],
187	    };
188	
189	    // Include location filter if specified (for location-specific pages)
190	    if (locationFilter && locationFilter !== 'all') {
191	      if (locationFilter.includes(',')) {
192	        totalMembersConditions.gamingLocation = {
193	          $in: locationFilter.split(','),
194	        };
195	      } else {
196	        totalMembersConditions.gamingLocation = locationFilter;
197	      }
198	    }
199	
200	    // Only include search filter if there's a search term
201	    if (searchTerm) {
202	      // Build search $or
203	      const searchOr = [
204	        { 'profile.firstName': { $regex: searchTerm, $options: 'i' } },
205	        { 'profile.lastName': { $regex: searchTerm, $options: 'i' } },
206	        { phoneNumber: { $regex: searchTerm, $options: 'i' } },
207	        { username: { $regex: searchTerm, $options: 'i' } },
208	      ];
209	
210	      // Combine deletedAt with search using $and
211	      totalMembersConditions.$and = [
212	        { $or: totalMembersConditions.$or as unknown[] },
213	        { $or: searchOr },
214	      ];
215	      delete totalMembersConditions.$or;
216	    }
217	
218	    const totalMembersCount = await Member.countDocuments(
219	      totalMembersConditions
220	    );
221	
222	    // ============================================================================
223	    // STEP 7: Aggregate member data with financial metrics
224	    // ============================================================================
225	    const memberSummary = await Member.aggregate([
226	      { $match: matchConditions },
227	      {
228	        $lookup: {
229	          from: 'gaminglocations',
230	          let: { memberLocation: '$gamingLocation' },
231	          pipeline: [
232	            {
233	              $match: {
234	                $expr: {
235	                  $or: [
236	                    { $eq: ['$_id', '$$memberLocation'] },
237	                    {
238	                      $eq: [
239	                        { $toString: '$_id' },
240	                        { $toString: '$$memberLocation' },
241	                      ],
242	                    },
243	                  ],
244	                },
245	              },
246	            },
247	          ],
248	          as: 'location',
249	        },
250	      },
251	      {
252	        $lookup: {
253	          from: 'machinesessions',
254	          let: { memberId: '$_id' },
255	          pipeline: [
256	            {
257	              $match: {
258	                $expr: {
259	                  $eq: ['$memberId', '$$memberId'],
260	                },
261	                // Apply date filter to sessions if specified (filter sessions by startTime)
262	                ...(Object.keys(sessionDateFilter).length > 0
263	                  ? sessionDateFilter
264	                  : {}),
265	              },
266	            },
267	          ],
268	          as: 'sessions',
269	        },
270	      },
271	      {
272	        $addFields: {
273	          locationName: {
274	            $ifNull: [
275	              { $arrayElemAt: ['$location.name', 0] },
276	              '$gamingLocation',
277	            ],
278	          },
279	          // Calculate financial metrics from sessions using correct fields from financial guide
280	          totalMoneyIn: {
281	            $reduce: {
282	              input: '$sessions',
283	              initialValue: 0,
284	              in: {
285	                $add: [
286	                  '$$value',
287	                  {
288	                    $ifNull: [
289	                      { $toDouble: '$$this.endMeters.movement.drop' },
290	                      0,
291	                    ],
292	                  },
293	                ],
294	              },
295	            },
296	          },
297	          totalMoneyOut: {
298	            $reduce: {
299	              input: '$sessions',
300	              initialValue: 0,
301	              in: {
302	                $add: [
303	                  '$$value',
304	                  {
305	                    $ifNull: [
306	                      {
307	                        $toDouble:
308	                          '$$this.endMeters.movement.totalCancelledCredits',
309	                      },
310	                      0,
311	                    ],
312	                  },
313	                ],
314	              },
315	            },
316	          },
317	          totalHandle: {
318	            $reduce: {
319	              input: '$sessions',
320	              initialValue: 0,
321	              in: {
322	                $add: [
323	                  '$$value',
324	                  {
325	                    $ifNull: [
326	                      { $toDouble: '$$this.endMeters.movement.coinIn' },
327	                      0,
328	                    ],
329	                  },
330	                ],
331	              },
332	            },
333	          },
334	        },
335	      },
336	      {
337	        $addFields: {
338	          winLoss: { $subtract: ['$totalMoneyIn', '$totalMoneyOut'] },
339	          grossRevenue: { $subtract: ['$totalMoneyIn', '$totalMoneyOut'] },
340	        },
341	      },
342	      {
343	        $project: {
344	          _id: 1,
345	          fullName: {
346	            $concat: [
347	              { $ifNull: ['$profile.firstName', ''] },
348	              ' ',
349	              { $ifNull: ['$profile.lastName', ''] },
350	            ],
351	          },
352	          address: { $ifNull: ['$profile.address', ''] },
353	          phoneNumber: { $ifNull: ['$phoneNumber', ''] },
354	          lastLogin: 1,
355	          createdAt: 1,
356	          locationName: 1,
357	          gamingLocation: 1,
358	          winLoss: 1,
359	          grossRevenue: 1,
360	          totalMoneyIn: 1,
361	          totalMoneyOut: 1,
362	          totalHandle: 1,
363	        },
364	      },
365	      {
366	        // Sort by createdAt (most recent first) - default for summary report
367	        $sort: { createdAt: -1 },
368	      },
369	      { $skip: skip },
370	      { $limit: limit },
371	    ]);
372	
373	    // ============================================================================
374	    // STEP 8: Calculate summary statistics
375	    // ============================================================================
376	    // Calculate active members (members who logged in within the last 30 days)
377	    // Active members should exclude date filter but include location filter if provided
378	    const thirtyDaysAgo = new Date();
379	    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
380	
381	    // Build conditions for active members (exclude date filter but include location filter if provided)
382	    // Start with totalMembersConditions and add lastLogin filter
383	    const activeMembersConditions: Record<string, unknown> = JSON.parse(
384	      JSON.stringify(totalMembersConditions)
385	    );
386	    activeMembersConditions.lastLogin = { $gte: thirtyDaysAgo };
387	
388	    // Get active members count from all members (not just paginated results)
389	    const activeMembersCount = await Member.countDocuments(
390	      activeMembersConditions
391	    );
392	
393	    // Calculate total locations count from locations collection, not from member data
394	    // Only count membership-enabled locations that are not soft-deleted in 2025 or later
395	    let totalLocationsCount = 0;
396	    try {
397	      const locationMatchConditions: Record<string, unknown> = {
398	        $and: [
399	          // Check both membershipEnabled and enableMembership fields for compatibility
400	          {
401	            $or: [{ membershipEnabled: true }, { enableMembership: true }],
402	          },
403	          {
404	            $or: [
405	              { deletedAt: null },
406	              { deletedAt: { $exists: false } },
407	              { deletedAt: { $lt: new Date('2025-01-01') } }, // Include locations deleted before 2025
408	            ],
409	          },
410	        ],
411	      };
412	
413	      totalLocationsCount = await GamingLocations.countDocuments(
414	        locationMatchConditions
415	      );
416	    } catch (error) {
417	      console.warn('Failed to fetch total locations count:', error);
418	      // Fallback to counting unique locations from member data
419	      totalLocationsCount = new Set(
420	        memberSummary.map(
421	          (memberItem: Record<string, unknown>) => memberItem.gamingLocation
422	        )
423	      ).size;
424	    }
425	
426	    const summaryStats = {
427	      totalMembers: totalMembersCount, // Total members excluding date filter
428	      totalLocations: totalLocationsCount,
429	      activeMembers: activeMembersCount, // Members who logged in within last 30 days
430	      recentMembers: memberSummary.filter(
431	        (memberItem: Record<string, unknown>) => {
432	          const weekAgo = new Date();
433	          weekAgo.setDate(weekAgo.getDate() - 7);
434	          return new Date(memberItem.createdAt as string) >= weekAgo;
435	        }
436	      ).length,
437	    };
438	
439	    // ============================================================================
440	    // STEP 9: Return paginated results with summary
441	    // ============================================================================
442	    const totalPages = Math.ceil(totalCount / limit);
443	    const hasNextPage = page < totalPages;
444	    const hasPrevPage = page > 1;
445	
446	    const duration = Date.now() - startTime;
447	    logRouteFetch(
448	      functionName,
449	      'GET',
450	      '/api/members/summary',
451	      memberSummary.length,
452	      user,
453	      duration
454	    );
455	
456	    if (duration > 1000) {
457	      console.warn(`[Members Summary API] Completed in ${duration}ms`);
458	    }
459	    return NextResponse.json({
460	      success: true,
461	      data: {
462	        members: memberSummary,
463	        summary: summaryStats,
464	        pagination: {
465	          page,
466	          limit,
467	          total: totalCount,
468	          totalPages,
469	          hasNext: hasNextPage,
470	          hasPrev: hasPrevPage,
471	        },
472	      },
473	    });
474	  } catch (error) {
475	    const duration = Date.now() - startTime;
476	    const errorMessage =
477	      error instanceof Error ? error.message : 'Internal server error';
478	    logRouteError(
479	      functionName,
480	      'GET',
481	      '/api/members/summary',
482	      errorMessage,
483	      user
484	    );
485	    console.error(
486	      `[Members Summary API] Error after ${duration}ms:`,
487	      errorMessage
488	    );
489	    return NextResponse.json({ error: errorMessage }, { status: 500 });
490	  }
491	}
