1	/**
2	 * Members Count API Route
3	 *
4	 * This route returns the count of members (not locations).
5	 *
6	 * @module app/api/members/count/route
7	 */
8	
9	import {
10	  getUserAccessibleLicenceesFromToken,
11	  getUserLocationFilter,
12	} from '@/app/api/lib/helpers/licenceeFilter';
13	import { getUserFromServer } from '@/app/api/lib/helpers/users/users';
14	import { connectDB } from '@/app/api/lib/middleware/db';
15	import { Member } from '@/app/api/lib/models/members';
16	import {
17	  logRouteFetch,
18	  logRouteError,
19	  extractUserFromRequest,
20	} from '@/app/api/lib/utils/routeLogger';
21	import type { PipelineStage } from 'mongoose';
22	import { NextRequest, NextResponse } from 'next/server';
23	
24	/**
25	 * Main GET handler for members count
26	 *
27	 * @param {string} licencee - Filter count by licencee name
28	 * @param {string} locationId - Filter count by specific location(s) (supports comma-separated list)
29	 * @param {string} machineTypeFilter - Filter by machine features ('LocalServersOnly', 'SMIBLocationsOnly', 'NoSMIBLocation', 'MembershipOnly')
30	 *
31	 * Flow:
32	 * 1. Parse licencee and location parameters
33	 * 2. Connect to database and authenticate user
34	 * 3. Get user location permissions
35	 * 4. Count members based on accessible locations
36	 * 5. Return count
37	 */
38	export async function GET(req: NextRequest) {
39	  const startTime = Date.now();
40	  const functionName = 'GET /api/members/count';
41	  const logUser = extractUserFromRequest(req);
42	
43	  try {
44	    // ============================================================================
45	    // STEP 1: Parse request parameters
46	    // ============================================================================
47	    const { searchParams } = new URL(req.url);
48	    const licencee = searchParams.get('licencee');
49	    const locationId = searchParams.get('locationId');
50	    const machineTypeFilter = searchParams.get('machineTypeFilter');
51	
52	    // ============================================================================
53	    // STEP 2: Connect to database and authenticate user
54	    // ============================================================================
55	    const db = await connectDB();
56	    if (!db) {
57	      return NextResponse.json(
58	        { error: 'Database connection failed', memberCount: 0 },
59	        { status: 500 }
60	      );
61	    }
62	
63	    const user = await getUserFromServer();
64	
65	    // Get user's accessible licencees
66	    const userAccessibleLicencees = await getUserAccessibleLicenceesFromToken();
67	
68	    // Get user's location permissions and roles
69	    const userLocationPermissions = ((
70	      user?.resourcePermissions as
71	        | Record<
72	            string,
73	            {
74	              resources?: Array<{ _id: string }>;
75	            }
76	          >
77	        | undefined
78	    )?.['gaming-locations']?.resources?.map(
79	      (resource: { _id: string }) => resource._id
80	    ) || []) as string[];
81	    const userRoles = (user?.roles || []) as string[];
82	
83	    // ============================================================================
84	    // STEP 3: Get user location permissions
85	    // ============================================================================
86	    const allowedLocationIds = await getUserLocationFilter(
87	      userAccessibleLicencees,
88	      licencee || undefined,
89	      userLocationPermissions,
90	      userRoles
91	    );
92	
93	    // ============================================================================
94	    // STEP 4: Build aggregation pipeline for members count with location filters
95	    // ============================================================================
96	    // Use aggregation to join members with locations for filtering
97	    const aggregationPipeline: PipelineStage[] = [
98	      {
99	        $match: {
100	          $or: [
101	            { deletedAt: null },
102	            { deletedAt: { $exists: false } },
103	            { deletedAt: { $lt: new Date('2025-01-01') } }, // Include items deleted before 2025
104	          ],
105	        },
106	      },
107	      {
108	        $lookup: {
109	          from: 'gaminglocations',
110	          localField: 'gamingLocation',
111	          foreignField: '_id',
112	          as: 'locationDetails',
113	        },
114	      },
115	      {
116	        $unwind: { path: '$locationDetails', preserveNullAndEmptyArrays: true },
117	      },
118	    ];
119	
120	    // Apply location access filter
121	    if (locationId) {
122	      if (locationId.includes(',')) {
123	        aggregationPipeline.push({
124	          $match: { gamingLocation: { $in: locationId.split(',') } },
125	        });
126	      } else {
127	        aggregationPipeline.push({
128	          $match: { gamingLocation: locationId },
129	        });
130	      }
131	    } else if (allowedLocationIds !== 'all') {
132	      // Apply location permissions
133	      if (allowedLocationIds.length === 0) {
134	        const duration = Date.now() - startTime;
135	        logRouteFetch(
136	          functionName,
137	          'GET',
138	          '/api/members/count',
139	          0,
140	          logUser,
141	          duration
142	        );
143	        return NextResponse.json({ memberCount: 0 });
144	      }
145	      aggregationPipeline.push({
146	        $match: { gamingLocation: { $in: allowedLocationIds } },
147	      });
148	    }
149	
150	    // Apply machine type filters (SMIB, No SMIB, Local Server, Membership)
151	    if (machineTypeFilter) {
152	      const filters = machineTypeFilter.split(',').filter(f => f.trim() !== '');
153	      const filterConditions: Record<string, unknown>[] = [];
154	
155	      filters.forEach(filter => {
156	        switch (filter.trim()) {
157	          case 'LocalServersOnly':
158	            filterConditions.push({ 'locationDetails.isLocalServer': true });
159	            break;
160	          case 'SMIBLocationsOnly':
161	            filterConditions.push({
162	              'locationDetails.noSMIBLocation': { $ne: true },
163	            });
164	            break;
165	          case 'NoSMIBLocation':
166	            filterConditions.push({ 'locationDetails.noSMIBLocation': true });
167	            break;
168	          case 'MembershipOnly':
169	            // Check both membershipEnabled and enableMembership fields for compatibility
170	            filterConditions.push({
171	              $or: [
172	                { 'locationDetails.membershipEnabled': true },
173	                { 'locationDetails.enableMembership': true },
174	              ],
175	            });
176	            break;
177	        }
178	      });
179	
180	      // Apply OR logic - location must match ANY of the selected filters
181	      // This allows users to see locations that match any combination of filters
182	      if (filterConditions.length > 0) {
183	        aggregationPipeline.push({ $match: { $or: filterConditions } });
184	      }
185	    }
186	
187	    // ============================================================================
188	    // STEP 5: Count members using aggregation
189	    // ============================================================================
190	    const countResult = await Member.aggregate([
191	      ...aggregationPipeline,
192	      { $count: 'total' },
193	    ]).exec();
194	    const memberCount = countResult[0]?.total || 0;
195	
196	    const duration = Date.now() - startTime;
197	    logRouteFetch(
198	      functionName,
199	      'GET',
200	      '/api/members/count',
201	      1,
202	      logUser,
203	      duration
204	    );
205	
206	    return NextResponse.json({ memberCount });
207	  } catch (err) {
208	    const errorMessage = err instanceof Error ? err.message : 'Server Error';
209	    logRouteError(
210	      functionName,
211	      'GET',
212	      '/api/members/count',
213	      errorMessage,
214	      logUser
215	    );
216	    return NextResponse.json(
217	      { error: errorMessage, memberCount: 0 },
218	      { status: 500 }
219	    );
220	  }
221	}
