1	/**
2	 * Check Unique Username/Email API Route
3	 *
4	 * This route checks if a username or email already exists in the database.
5	 * Used for real-time validation in member creation/editing forms.
6	 *
7	 * @module app/api/members/check-unique/route
8	 */
9	
10	import { connectDB } from '@/app/api/lib/middleware/db';
11	import { Member } from '@/app/api/lib/models/members';
12	import {
13	  logRouteFetch,
14	  logRouteError,
15	  extractUserFromRequest,
16	} from '@/app/api/lib/utils/routeLogger';
17	import { NextRequest, NextResponse } from 'next/server';
18	
19	/**
20	 * GET handler for checking username/email uniqueness
21	 *
22	 * @param {string} username - Username to check for availability
23	 * @param {string} email - Email address to check for availability
24	 * @param {string} excludeId - Member ID to exclude from uniqueness check (for edits)
25	 *
26	 * Flow:
27	 * 1. Parse query parameters (username, email, excludeId)
28	 * 2. Connect to database
29	 * 3. Check if username exists (if provided)
30	 * 4. Check if email exists (if provided)
31	 * 5. Return availability status
32	 */
33	export async function GET(req: NextRequest) {
34	  const startTime = Date.now();
35	  const functionName = 'GET /api/members/check-unique';
36	  const user = extractUserFromRequest(req);
37	
38	  try {
39	    // ============================================================================
40	    // STEP 1: Parse query parameters
41	    // ============================================================================
42	    const { searchParams } = new URL(req.url);
43	    const username = searchParams.get('username');
44	    const email = searchParams.get('email');
45	    const excludeId = searchParams.get('excludeId'); // For edit mode - exclude current member
46	
47	    // ============================================================================
48	    // STEP 2: Connect to database
49	    // ============================================================================
50	    await connectDB();
51	
52	    // ============================================================================
53	    // STEP 3: Check username uniqueness
54	    // ============================================================================
55	    let usernameAvailable = true;
56	    if (username && username.trim()) {
57	      const query: Record<string, unknown> = { username: username.trim() };
58	      // Exclude current member if editing
59	      if (excludeId) {
60	        query._id = { $ne: excludeId };
61	      }
62	      const existingUsername = await Member.findOne(query);
63	      usernameAvailable = !existingUsername;
64	    }
65	
66	    // ============================================================================
67	    // STEP 4: Check email uniqueness
68	    // ============================================================================
69	    let emailAvailable = true;
70	    if (email && email.trim()) {
71	      const query: Record<string, unknown> = {
72	        'profile.email': email.trim(),
73	      };
74	      // Exclude current member if editing
75	      if (excludeId) {
76	        query._id = { $ne: excludeId };
77	      }
78	      const existingEmail = await Member.findOne(query);
79	      emailAvailable = !existingEmail;
80	    }
81	
82	    // ============================================================================
83	    // STEP 5: Return availability status
84	    // ============================================================================
85	    const duration = Date.now() - startTime;
86	    logRouteFetch(
87	      functionName,
88	      'GET',
89	      '/api/members/check-unique',
90	      1,
91	      user,
92	      duration
93	    );
94	
95	    return NextResponse.json({
96	      usernameAvailable,
97	      emailAvailable,
98	      username: username ? username.trim() : null,
99	      email: email ? email.trim() : null,
100	    });
101	  } catch (error) {
102	    const errorMessage =
103	      error instanceof Error ? error.message : 'Internal server error';
104	    logRouteError(
105	      functionName,
106	      'GET',
107	      '/api/members/check-unique',
108	      errorMessage,
109	      user
110	    );
111	    return NextResponse.json({ error: errorMessage }, { status: 500 });
112	  }
113	}
