1	/**
2	 * GET /api/members/send-verification-sms
3	 *
4	 * Sends an SMS verification code to a member's phone number via the Infobip
5	 * gateway. NOT called directly by any frontend page — this endpoint is invoked
6	 * server-side only (e.g. from member-registration or profile-update flows that
7	 * need to trigger SMS delivery on behalf of the user). Generates a new
8	 * verification code, stores it on the member document with a timestamp, and
9	 * dispatches the message. Activity is logged on both success and failure.
10	 *
11	 * Query parameters:
12	 * @param memberId    {string} Required. The ID of the member record to attach the
13	 *   verification code to.
14	 * @param phoneNumber {string} Required. E.164-format phone number to send the SMS to
15	 *   (e.g. '+18681234567'). Must pass basic format validation before dispatch.
16	 *
17	 * @module app/api/members/send-verification-sms/route
18	 */
19	
20	import { logActivity } from '@/app/api/lib/helpers/activityLogger';
21	import { getUserFromServer } from '@/app/api/lib/helpers/users';
22	import { sendVerificationSMS } from '@/app/api/lib/helpers/sms';
23	import { connectDB } from '@/app/api/lib/middleware/db';
24	import {
25	  logRouteFetch,
26	  logRouteError,
27	  extractUserFromRequest,
28	} from '@/app/api/lib/utils/routeLogger';
29	import { NextRequest, NextResponse } from 'next/server';
30	
31	export async function GET(req: NextRequest) {
32	  const startTime = Date.now();
33	  const functionName = 'GET /api/members/send-verification-sms';
34	  const logUser = extractUserFromRequest(req);
35	
36	  try {
37	    // ============================================================================
38	    // STEP 1: Connect to Database
39	    // ============================================================================
40	    await connectDB();
41	
42	    // ============================================================================
43	    // STEP 2: Parse Query Parameters
44	    // ============================================================================
45	    const { searchParams } = new URL(req.url);
46	    const memberId = searchParams.get('memberId');
47	    const phoneNumber = searchParams.get('phoneNumber');
48	
49	    if (!memberId || !phoneNumber) {
50	      logRouteError(
51	        functionName,
52	        'GET',
53	        '/api/members/send-verification-sms',
54	        'Missing required parameters',
55	        logUser
56	      );
57	      return NextResponse.json(
58	        {
59	          success: false,
60	          error: 'Missing required parameters: memberId and phoneNumber',
61	        },
62	        { status: 400 }
63	      );
64	    }
65	
66	    const phoneRegex = /^\+?[1-9]\d{1,14}$/;
67	
68	    if (!phoneRegex.test(phoneNumber)) {
69	      logRouteError(
70	        functionName,
71	        'GET',
72	        '/api/members/send-verification-sms',
73	        'Invalid phone number format',
74	        logUser
75	      );
76	      return NextResponse.json(
77	        { success: false, error: 'Invalid phone number format' },
78	        { status: 400 }
79	      );
80	    }
81	
82	    // ============================================================================
83	    // STEP 3: Send SMS and update member record
84	    // ============================================================================
85	    const result = await sendVerificationSMS(memberId, phoneNumber);
86	
87	    // ============================================================================
88	    // STEP 4: Log Activity (Success)
89	    // ============================================================================
90	    const user = await getUserFromServer();
91	    if (user) {
92	      await logActivity({
93	        action: 'sms_success',
94	        details: `Successfully sent verification SMS to ${phoneNumber} (Member ID: ${memberId}). Status: ${result.statusName}`,
95	        userId: String(user._id || user.id || user.sub),
96	        username:
97	          (user.emailAddress as string) ||
98	          (user.username as string) ||
99	          'unknown',
100	        membershipLog: true,
101	        metadata: {
102	          resource: 'sms',
103	          resourceId: memberId,
104	          resourceName: phoneNumber,
105	          phone: phoneNumber,
106	          messageId: result.messageId,
107	          status: result.statusName,
108	          description: result.statusDescription,
109	        },
110	      });
111	    }
112	
113	    // ============================================================================
114	    // STEP 5: Return Success Response
115	    // ============================================================================
116	    const duration = Date.now() - startTime;
117	    logRouteFetch(
118	      functionName,
119	      'GET',
120	      '/api/members/send-verification-sms',
121	      1,
122	      logUser,
123	      duration
124	    );
125	
126	    return NextResponse.json({
127	      success: true,
128	      message: 'Verification code sent successfully',
129	      data: {
130	        messageId: result.messageId,
131	        phone: result.phone,
132	        status: result.statusName,
133	        statusDescription: result.statusDescription,
134	      },
135	    });
136	  } catch (error: unknown) {
137	    const errorMessage =
138	      error instanceof Error ? error.message : 'Unknown server error';
139	    const { searchParams } = new URL(req.url);
140	    const memberId = searchParams.get('memberId');
141	    const phoneNumber = searchParams.get('phoneNumber');
142	
143	    logRouteError(
144	      functionName,
145	      'GET',
146	      '/api/members/send-verification-sms',
147	      errorMessage,
148	      logUser
149	    );
150	    console.error(
151	      `[SMS API] Failed to send verification SMS to memberId ${memberId}:`,
152	      errorMessage
153	    );
154	
155	    // Log Activity (Failure)
156	    const user = await getUserFromServer();
157	    if (user) {
158	      try {
159	        await logActivity({
160	          action: 'sms_failed',
161	          details: `Failed to send verification SMS to ${phoneNumber} (Member ID: ${memberId}). Error: ${errorMessage}`,
162	          userId: String(user._id || user.id || user.sub),
163	          username:
164	            (user.emailAddress as string) ||
165	            (user.username as string) ||
166	            'unknown',
167	          membershipLog: true,
168	          metadata: {
169	            resource: 'sms',
170	            resourceId: memberId || 'unknown',
171	            resourceName: phoneNumber || 'unknown',
172	            error: errorMessage,
173	          },
174	        });
175	      } catch (logErr) {
176	        console.error('[SMS API] Failed to log failure activity:', logErr);
177	      }
178	    }
179	
180	    // Distinguish config errors (500) from request/carrier errors (400)
181	    const isConfigError = errorMessage.includes('configuration missing');
182	    return NextResponse.json(
183	      { success: false, error: errorMessage },
184	      { status: isConfigError ? 500 : 400 }
185	    );
186	  }
187	}
