1	/**
2	 * Member Machine Events API Route
3	 *
4	 * This route handles fetching machine events for a specific member and machine.
5	 * It supports:
6	 * - Filtering by event type, event description, and game
7	 * - Pagination
8	 * - Optimized queries with indexing considerations
9	 * - Unique filter values for frontend dropdowns
10	 *
11	 * @module app/api/members/[id]/sessions/[machineId]/events/route
12	 */
13	
14	import { MachineEvent } from '@/app/api/lib/models/machineEvents';
15	import { connectDB } from '@/app/api/lib/middleware/db';
16	import {
17	  logRouteFetch,
18	  logRouteError,
19	  extractUserFromRequest,
20	} from '@/app/api/lib/utils/routeLogger';
21	import type { MachineEventDocument } from '@shared/types';
22	import { NextRequest, NextResponse } from 'next/server';
23	
24	/**
25	 * GET /api/members/[id]/sessions/[machineId]/events
26	 *
27	 * Fetches paginated machine events for a specific machine, scoped to the member's
28	 * context. Also returns the full set of unique `eventType`, description, and game
29	 * values so the frontend can populate filter dropdowns without a separate request.
30	 *
31	 * URL params:
32	 * @param {string} machineId - Required (path). The string `_id` of the machine whose events are fetched.
33	 *
34	 * Query params:
35	 * @param {string} [eventType] - Optional. Exact match filter on the event's `eventType` field
36	 *                             (e.g. `"GAME_EVENT"`, `"CASH_EVENT"`).
37	 * @param {string} [event] - Optional. Case-insensitive partial-match filter on the event `description`
38	 *                             field (applied as a regex).
39	 * @param {string} [game] - Optional. Case-insensitive partial-match filter on `gameName`
40	 *                             (applied as a regex).
41	 * @param {number} [page] - Optional. 1-based page number (default: 1).
42	 * @param {number} [limit] - Optional. Number of events per page (default: 10).
43	 */
44	export async function GET(request: NextRequest) {
45	  const startTime = Date.now();
46	  const functionName = 'GET /api/members/[id]/sessions/[machineId]/events';
47	  const user = extractUserFromRequest(request);
48	
49	  try {
50	    // ============================================================================
51	    // STEP 1: Parse route parameters
52	    // ============================================================================
53	    const { pathname, searchParams } = request.nextUrl;
54	    const parts = pathname.split('/');
55	    const machineId = parts[parts.length - 2];
56	    // id is not used in this route, so we don't need to extract it
57	
58	    const eventType = searchParams.get('eventType');
59	    const event = searchParams.get('event');
60	    const game = searchParams.get('game');
61	    const page = parseInt(searchParams.get('page') || '1');
62	    const limit = parseInt(searchParams.get('limit') || '10');
63	
64	    // ============================================================================
65	    // STEP 2: Connect to database
66	    // ============================================================================
67	    await connectDB();
68	
69	    // ============================================================================
70	    // STEP 3: Build query with filters
71	    // ============================================================================
72	    const query: Record<string, unknown> = { machine: machineId };
73	
74	    if (eventType) {
75	      query.eventType = eventType;
76	    }
77	
78	    if (event) {
79	      query.description = { $regex: event, $options: 'i' };
80	    }
81	
82	    if (game) {
83	      query.gameName = { $regex: game, $options: 'i' };
84	    }
85	
86	    // ============================================================================
87	    // STEP 4: Fetch events with pagination
88	    // ============================================================================
89	    const skip = (page - 1) * limit;
90	
91	    const events = await MachineEvent.find(query)
92	      .select({
93	        _id: 1,
94	        eventType: 1,
95	        description: 1,
96	        command: 1,
97	        gameName: 1,
98	        date: 1,
99	        eventLogLevel: 1,
100	        eventSuccess: 1,
101	        sequence: 1,
102	      })
103	      .sort({ date: -1 })
104	      .skip(skip)
105	      .limit(limit)
106	      .lean<MachineEventDocument[]>();
107	
108	    // ============================================================================
109	    // STEP 5: Get total count for pagination
110	    // ============================================================================
111	    const totalEvents = await MachineEvent.countDocuments(query);
112	
113	    // ============================================================================
114	    // STEP 6: Get unique filter values using aggregation
115	    // ============================================================================
116	    const filterPipeline = [
117	      { $match: { machine: machineId } },
118	      {
119	        $group: {
120	          _id: null,
121	          eventTypes: { $addToSet: '$eventType' },
122	          events: { $addToSet: '$description' },
123	          games: { $addToSet: '$gameName' },
124	        },
125	      },
126	      {
127	        $project: {
128	          eventTypes: {
129	            $filter: { input: '$eventTypes', cond: { $ne: ['$$this', null] } },
130	          },
131	          events: {
132	            $filter: { input: '$events', cond: { $ne: ['$$this', null] } },
133	          },
134	          games: {
135	            $filter: { input: '$games', cond: { $ne: ['$$this', null] } },
136	          },
137	        },
138	      },
139	    ];
140	
141	    const filterResults = await MachineEvent.aggregate(filterPipeline);
142	
143	    const uniqueEventTypes = filterResults[0]?.eventTypes || [];
144	    const uniqueEvents = filterResults[0]?.events || [];
145	    const uniqueGames = filterResults[0]?.games || [];
146	
147	    // ============================================================================
148	    // STEP 7: Return paginated events with filter options
149	    // ============================================================================
150	    const duration = Date.now() - startTime;
151	    logRouteFetch(
152	      functionName,
153	      'GET',
154	      '/api/members/[id]/sessions/[machineId]/events',
155	      events.length,
156	      user,
157	      duration
158	    );
159	
160	    if (duration > 1000) {
161	      console.warn(`[Member Sessions Events API] Completed in ${duration}ms`);
162	    }
163	    return NextResponse.json({
164	      success: true,
165	      data: {
166	        events,
167	        pagination: {
168	          currentPage: page,
169	          totalPages: Math.ceil(totalEvents / limit),
170	          totalEvents,
171	          hasNextPage: page * limit < totalEvents,
172	          hasPrevPage: page > 1,
173	        },
174	        filters: {
175	          eventTypes: uniqueEventTypes.sort(),
176	          events: uniqueEvents.sort(),
177	          games: uniqueGames.sort(),
178	        },
179	      },
180	    });
181	  } catch (error) {
182	    const duration = Date.now() - startTime;
183	    const errorMessage =
184	      error instanceof Error ? error.message : 'Failed to fetch machine events';
185	    logRouteError(
186	      functionName,
187	      'GET',
188	      '/api/members/[id]/sessions/[machineId]/events',
189	      errorMessage,
190	      user
191	    );
192	    console.error(
193	      `[Member Machine Events API] Error after ${duration}ms:`,
194	      errorMessage
195	    );
196	    return NextResponse.json(
197	      { success: false, error: errorMessage },
198	      { status: 500 }
199	    );
200	  }
201	}
