56	// ============================================================================
57	// GET: Fetch Member with Location
58	// ============================================================================
59	
60	/**
61	 * Fetches a member with its associated location name via aggregation lookup.
62	 *
63	 * @param {string} memberId - Member ID to fetch
64	 * @returns {Promise<MemberWithLocation | null>} Member with location name or null
65	 */
66	export async function fetchMemberWithLocation(
67	  memberId: string
68	): Promise<MemberWithLocation | null> {
69	  const pipeline: PipelineStage[] = [
70	    { $match: { _id: memberId } },
71	    {
72	      $lookup: {
73	        from: 'gaminglocations',
74	        let: { memberLocation: '$gamingLocation' },
75	        pipeline: [
76	          {
77	            $match: {
78	              $expr: {
79	                $or: [
80	                  { $eq: ['$_id', '$$memberLocation'] },
81	                  {
82	                    $eq: [
83	                      { $toString: '$_id' },
84	                      { $toString: '$$memberLocation' },
85	                    ],
86	                  },
87	                ],
88	              },
89	            },
90	          },
91	        ],
92	        as: 'locationInfo',
93	      },
94	    },
95	    {
96	      $addFields: {
97	        locationName: { $arrayElemAt: ['$locationInfo.name', 0] },
98	      },
99	    },
100	    {
101	      $project: {
102	        locationInfo: 0,
103	      },
104	    },
105	  ];
106	
107	  const members = await Member.aggregate<MemberWithLocation>(
108	    pipeline
109	  ).exec();
110	
111	  return members[0] || null;
112	}
