114	// ============================================================================
115	// PUT: Update Member Profile Fields
116	// ============================================================================
117	
118	/**
119	 * Updates member profile fields from input, preserving existing fields and identification.
120	 *
121	 * @param {Record<string, unknown> | undefined} profile - Existing profile fields
122	 * @param {MemberProfileInput | undefined} profileInput - New profile field values
123	 * @returns {Record<string, unknown> | null} Updated profile fields or null
124	 */
125	export function updateMemberProfileFields(
126	  profile: Record<string, unknown> | undefined,
127	  profileInput: MemberProfileInput | undefined
128	): Record<string, unknown> | null {
129	  if (!profileInput || profileInput === undefined) return null;
130	
131	  const existingIdentification = (profile?.indentification as
132	    | { number?: string; type?: string }
133	    | undefined) || { number: '', type: '' };
134	
135	  const safeIdentification = {
136	    number: existingIdentification.number || '',
137	    type: existingIdentification.type || '',
138	  };
139	
140	  const updatedProfile: Record<string, unknown> = {
141	    firstName: (profile?.firstName as string) || '',
142	    lastName: (profile?.lastName as string) || '',
143	    email: (profile?.email as string) || '',
144	    occupation: (profile?.occupation as string) || '',
145	    address: (profile?.address as string) || '',
146	    gender: (profile?.gender as string) || '',
147	    dob: (profile?.dob as string) || '',
148	    indentification: safeIdentification,
149	  };
150	
151	  const trimString = (value: unknown): string => {
152	    if (typeof value === 'string') return value.trim();
153	    return '';
154	  };
155	
156	  const updateField = (
157	    key: string,
158	    inputValue: unknown
159	  ): void => {
160	    if (inputValue !== undefined) {
161	      updatedProfile[key] = trimString(inputValue);
162	    }
163	  };
164	
165	  updateField('firstName', profileInput.firstName);
166	  updateField('lastName', profileInput.lastName);
167	  updateField('email', profileInput.email);
168	  updateField('occupation', profileInput.occupation);
169	  updateField('address', profileInput.address);
170	  updateField('gender', profileInput.gender);
171	  updateField('dob', profileInput.dob);
172	
173	  updatedProfile.indentification = safeIdentification;
174	
175	  return updatedProfile;
176	}
