178	// ============================================================================
179	// PUT: Check Unique Field (email/username)
180	// ============================================================================
181	
182	/**
183	 * Checks if a member field value (username or email) is already taken by another member.
184	 *
185	 * @param {'username' | 'profile.email'} field - Field to check
186	 * @param {string} value - Value to check for uniqueness
187	 * @param {string} excludeMemberId - Member ID to exclude from check
188	 * @returns {Promise<boolean>} True if the value is already in use
189	 */
190	export async function checkMemberFieldUniqueness(
191	  field: 'username' | 'profile.email',
192	  value: string,
193	  excludeMemberId: string
194	): Promise<boolean> {
195	  const query =
196	    field === 'username'
197	      ? { username: value, _id: { $ne: excludeMemberId } }
198	      : { 'profile.email': value, _id: { $ne: excludeMemberId } };
199	
200	  const existing = await Member.findOne(query);
201	  return existing !== null;
202	}
