204	// ============================================================================
205	// PUT: Update Member Fields from Body
206	// ============================================================================
207	
208	/**
209	 * Applies a field update to a member object, trimming string values.
210	 *
211	 * @template T - Value type
212	 * @param {Record<string, unknown>} member - Member object to update
213	 * @param {string} field - Field name to set
214	 * @param {T} value - Value to set
215	 */
216	export function applyMemberFieldUpdate<T>(
217	  member: Record<string, unknown>,
218	  field: string,
219	  value: T
220	): void {
221	  if (value !== undefined) {
222	    if (typeof value === 'string') {
223	      member[field] = value.trim();
224	    } else {
225	      member[field] = value;
226	    }
227	  }
228	}
