230	// ============================================================================
231	// DELETE: Soft Delete Member
232	// ============================================================================
233	
234	export type DeleteMemberResult = {
235	  success: boolean;
236	  member: MemberDocument | null;
237	};
238	
239	/**
240	 * Soft-deletes a member by setting its deletedAt timestamp.
241	 *
242	 * @param {string} memberId - Member ID to delete
243	 * @returns {Promise<DeleteMemberResult>} Result with success status and deleted member
244	 */
245	export async function softDeleteMember(
246	  memberId: string
247	): Promise<DeleteMemberResult> {
248	  const member = await Member.findOne({ _id: memberId });
249	
250	  if (!member) {
251	    return { success: false, member: null };
252	  }
253	
254	  member.deletedAt = new Date();
255	  await member.save();
256	
257	  return {
258	    success: true,
259	    member: member.toObject ? member.toObject() : member,
260	  };
261	}
