264	// DELETE: Build Activity Log Params
265	// ============================================================================
266	
267	/**
268	 * Builds activity log parameters for a member deletion event.
269	 *
270	 * @param {string} memberId - Deleted member ID
271	 * @param {MemberDocument} member - Deleted member document
272	 * @param {{ _id: string; emailAddress?: string }} currentUser - Currently authenticated user
273	 * @param {NextRequest} request - HTTP request for IP extraction
274	 * @returns {{ action: string; details: string; ipAddress?: string; userId: string; username: string; metadata: DeleteActivityMetadata }}
275	 */
276	export function buildDeleteActivityParams(
277	  memberId: string,
278	  member: MemberDocument,
279	  currentUser: { _id: string; emailAddress?: string },
280	  request: NextRequest
281	): {
282	  action: string;
283	  details: string;
284	  ipAddress?: string;
285	  userId: string;
286	  username: string;
287	  metadata: DeleteActivityMetadata;
288	} {
289	  return {
290	    action: 'DELETE',
291	    details: `Deleted member "${(member.username as string) || memberId}"`,
292	    ipAddress: getClientIP(request) || undefined,
293	    userId: currentUser._id,
294	    username: currentUser.emailAddress || '',
295	    metadata: {
296	      resource: 'member',
297	      resourceId: memberId,
298	      resourceName: member.username || memberId,
299	      changes: [],
300	      previousData: member,
301	      newData: null,
302	    },
303	  };
304	}
