36	const formatLoginTime = (
37	  dateTime: string | Date | null | undefined
38	): string => {
39	  if (!dateTime) {
40	    return 'N/A';
41	  }
42	
43	  try {
44	    const date = typeof dateTime === 'string' ? new Date(dateTime) : dateTime;
45	    if (isNaN(date.getTime())) {
46	      return 'Invalid Date';
47	    }
48	
49	    const dateStr = new Intl.DateTimeFormat('en-US', {
50	      month: 'short',
51	      day: '2-digit',
52	    }).format(date);
53	
54	    const timeStr = new Intl.DateTimeFormat('en-US', {
55	      hour: '2-digit',
56	      minute: '2-digit',
57	      hour12: true,
58	    }).format(date);
59	
60	    return `${dateStr}\n${timeStr}`;
61	  } catch {
62	    return 'Invalid Date';
63	  }
64	};
