236	export default function MembersPlayerSessionTable({
237	  sessions,
238	  currentPage,
239	  totalPages,
240	  onPageChange,
241	  sortOption,
242	  sortOrder,
243	  onSort,
244	}: MembersPlayerSessionTableProps) {
245	  // ============================================================================
246	  // State & Hooks
247	  // ============================================================================
248	  const { formatAmount, shouldShowCurrency } = useCurrencyFormat();
249	  // ============================================================================
250	  // Handlers
251	  // ============================================================================
252	  const handleFirstPage = () => onPageChange(0);
253	  const handleLastPage = () => onPageChange(totalPages - 1);
254	  const handlePrevPage = () => currentPage > 0 && onPageChange(currentPage - 1);
255	  const handleNextPage = () =>
256	    currentPage < totalPages - 1 && onPageChange(currentPage + 1);
257	
258	  // ============================================================================
259	  // Computed
260	  // ============================================================================
261	  // Sort sessions based on current sort option and order
262	  const sortedSessions = useMemo(() => {
263	    return [...sessions].sort((a, b) => {
264	      let aValue: string | number;
265	      let bValue: string | number;
266	
267	      switch (sortOption) {
268	        case 'time':
269	          // Handle both individual sessions (Date objects) and grouped data (formatted strings)
270	          if (typeof a.time === 'string' && typeof b.time === 'string') {
271	            // For grouped data, sort by the string representation
272	            aValue = a.time;
273	            bValue = b.time;
274	          } else {
275	            // For individual sessions, sort by timestamp
276	            aValue = a.time ? new Date(a.time).getTime() : 0;
277	            bValue = b.time ? new Date(b.time).getTime() : 0;
278	          }
279	          break;
280	        case 'sessionLength':
281	          aValue = a.sessionLength || 'N/A';
282	          bValue = b.sessionLength || 'N/A';
283	          break;
284	        case 'moneyIn':
285	          aValue = a.moneyIn || 0;
286	          bValue = b.moneyIn || 0;
287	          break;
288	        case 'moneyOut':
289	          aValue = a.moneyOut || 0;
290	          bValue = b.moneyOut || 0;
291	          break;
292	        case 'jackpot':
293	          aValue = a.jackpot || 0;
294	          bValue = b.jackpot || 0;
295	          break;
296	        case 'wonLess':
297	          aValue = a.wonLess || 0;
298	          bValue = b.wonLess || 0;
299	          break;
300	        case 'points':
301	          aValue = a.points || 0;
302	          bValue = b.points || 0;
303	          break;
304	        case 'gamesPlayed':
305	          aValue = a.gamesPlayed || 0;
306	          bValue = b.gamesPlayed || 0;
307	          break;
308	        case 'gamesWon':
309	          aValue = a.gamesWon || 0;
310	          bValue = b.gamesWon || 0;
311	          break;
312	        case 'coinIn':
313	          aValue = a.coinIn || 0;
314	          bValue = b.coinIn || 0;
315	          break;
316	        case 'coinOut':
317	          aValue = a.coinOut || 0;
318	          bValue = b.coinOut || 0;
319	          break;
320	        default:
321	          return 0;
322	      }
323	
324	      if (typeof aValue === 'string' && typeof bValue === 'string') {
325	        return sortOrder === 'asc'
326	          ? aValue.localeCompare(bValue)
327	          : bValue.localeCompare(aValue);
328	      }
329	
330	      if (sortOrder === 'asc') {
331	        return aValue < bValue ? -1 : aValue > bValue ? 1 : 0;
332	      } else {
333	        return aValue > bValue ? -1 : aValue < bValue ? 1 : 0;
334	      }
335	    });
336	  }, [sessions, sortOption, sortOrder]);
